      const h = handlers.adminMe ?? jsonStatus(401);
      return typeof h === 'function' ? h() : h;
    }
    return handlers.fallback ?? jsonOk({});
  };
  globalThis.fetch = fetchImpl as unknown as typeof fetch;
}


