    handle.rebuild({
      database: stubDb,
      providers: [{ kind: 'google', clientId: 'x', clientSecret: 'y' }],
    });
    const after = handle.current();
    expect(after).not.toBe(before);
  });

  it('rebuild() does not throw on a syntactically-valid-but-bogus secret', () => {
    expect(() =>
      handle.rebuild({
        database: stubDb,
        providers: [
