import { AsyncLocalStorage } from 'node:async_hooks';
import { APIError } from 'better-auth';

/**
 * Request-scoped carrier for the session token better-auth mints during a
 * sign-in flow. `handler.ts`'s `databaseHooks.session.create.after` writes
 * `box.token`; `plugin.ts`'s forwardToBetterAuth runs the better-auth call
 * inside `sessionTokenALS.run(box, …)` and, after it returns, re-issues the
 * token as the http-server-signed `ax_auth_session` cookie. This is how the
 * single session store (`auth_better_v1_sessions`) and the single cookie
 * (`ax_auth_session`) stay the source of truth even though better-auth would
 * otherwise set its own cookie.
 */
export const sessionTokenALS = new AsyncLocalStorage<{ token?: string }>();

/** Parse the provider's `allowed_domains` (comma-separated) into lowercased bare domains. */
export function parseDomains(raw: string | null | undefined): string[] {
  if (typeof raw !== 'string') return [];
  return raw
    .split(',')
    .map((d) => d.trim().toLowerCase())
    .filter((d) => d.length > 0);
}

/** The domain portion of an email (after the last `@`), lowercased; '' if malformed. */
export function emailDomain(email: string): string {
  const at = email.lastIndexOf('@');
  if (at < 0 || at === email.length - 1) return '';
  return email.slice(at + 1).toLowerCase();
}

/**
 * Authorization gate for Google provisioning. Empty `allowed` ⇒ open.
 * Throws better-auth's `APIError` (FORBIDDEN) so a rejected sign-in becomes a
 * clean callback-error redirect rather than a 500. Message is generic — it
 * never echoes which domains are allowed.
 */
export function assertDomainAllowed(email: string, allowed: string[]): void {
  if (allowed.length === 0) return;
  if (!allowed.includes(emailDomain(email))) {
    throw new APIError('FORBIDDEN', { message: 'email domain not permitted' });
  }
}
```
> Note: `PluginError` is imported in the test only to keep the import style consistent if you assert on error type; the helper throws `APIError`, so the test asserts `.toThrow()` generically. (Leave the `PluginError` import out if your linter flags it unused — adjust the test import to only what it uses.)

